def test_tc_gw_speed_001_zero_speed(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs, 'No GW_VehicleStatus messages received'
    for msg in msgs:
        assert decode_gw_speed_kmh(msg) == 0.0

